+    assert(result->affiliation() == FREE, "New region must be free");
+    result->set_affiliation(affiliation);
+    result->make_regular_allocation(affiliation);
+    partitions()->one_region_is_no_longer_empty(ALLOC_PARTITION);
+    new_region = true;
